#!/bin/bash
set -e
echo "=== Добавляем input_tfidf_json в fieldMap ==="

echo "" | base64 -d > /opt/seo-genius-v4/frontend/src/views/CreateTaskPage.vue

grep -q "input_tfidf_json" /opt/seo-genius-v4/frontend/src/views/CreateTaskPage.vue && echo "OK: input_tfidf_json в fieldMap" || echo "ERROR!"

echo ""
echo "=== Пересборка frontend ==="
cd /opt/seo-genius-v4
docker compose build --no-cache frontend
docker compose up -d frontend

sleep 3
docker compose ps | grep frontend
echo ""
echo "=== Готово! ==="
